#include <vector>
#include <map>
#include <algorithm>
#include <cmath>

using namespace std;

/**
 * @brief Generates a map where keys are possible subset XOR sums 
 * and values are the maximum size of a subset achieving that XOR sum.
 * 
 * @param nums_slice The segment of the array to process.
 * @return map<long long, int> Map of {XOR_sum: max_size}.
 */
map<long long, int> generate_xor_map(const vector<long long>& nums_slice) {
    map<long long, int> m;
    int L = nums_slice.size();

    // Iterate through all 2^L subsets using bitmasks
    // 1LL << L ensures calculation uses long long for large L, though L <= 20 here.
    for (long long i = 0; i < (1LL << L); ++i) {
        long long current_xor = 0;
        int current_size = 0;

        for (int j = 0; j < L; ++j) {
            if ((i >> j) & 1) {
                current_xor ^= nums_slice[j];
                current_size++;
            }
        }

        // Store the maximum size found for this XOR sum
        if (m.find(current_xor) == m.end() || current_size > m[current_xor]) {
            m[current_xor] = current_size;
        }
    }
    return m;
}

long long solve(std::vector<long long> nums, long long target) {
    int N = nums.size();

    if (N == 0) {
        return (target == 0) ? 0 : -1;
    }

    // Split the array into two halves for Meet-in-the-Middle
    int N1 = N / 2;

    vector<long long> A(nums.begin(), nums.begin() + N1);
    vector<long long> B(nums.begin() + N1, nums.end());

    // Generate maps for both halves
    map<long long, int> mapA = generate_xor_map(A);
    map<long long, int> mapB = generate_xor_map(B);

    int max_total_size = -1;

    // Combine results: Iterate through mapA and check required complement in mapB
    for (const auto& pairA : mapA) {
        long long XA = pairA.first;
        int SA = pairA.second;

        // We need XA ^ XB = target, so XB = target ^ XA
        long long X_req_B = target ^ XA;

        if (mapB.count(X_req_B)) {
            int SB = mapB[X_req_B];
            int current_total_size = SA + SB;

            if (current_total_size > max_total_size) {
                max_total_size = current_total_size;
            }
        }
    }

    if (max_total_size == -1) {
        // No subset combination yields the target XOR sum
        return -1;
    } else {
        // Minimum removals = Total elements - Maximum remaining elements
        return N - max_total_size;
    }
}

