#include <vector>
#include <unordered_map>
#include <algorithm>
#include <cmath>

using namespace std;

// Helper function to generate XOR sums and max sizes for a segment
// Maps XOR_sum -> Maximum subset size yielding that XOR_sum
unordered_map<long long, int> generate_map(const vector<long long>& nums, int start, int end) {
    unordered_map<long long, int> m;
    int count = end - start;

    // Iterate through all 2^count subsets using bitmasks
    // Since count <= 20, 2^count fits within standard integer types for loop control.
    for (int i = 0; i < (1 << count); ++i) {
        long long current_xor = 0;
        int current_size = 0;

        for (int j = 0; j < count; ++j) {
            // Check the j-th bit of i
            if ((i >> j) & 1) {
                current_xor ^= nums[start + j];
                current_size++;
            }
        }

        // Store the maximum size found for this XOR sum
        if (m.find(current_xor) == m.end() || current_size > m[current_xor]) {
            m[current_xor] = current_size;
        }
    }
    return m;
}


long long solve(std::vector<long long> nums, long long target) {
    int N = nums.size();
    if (N == 0) {
        return (target == 0) ? 0 : -1;
    }

    int N_L = N / 2;

    // 1. Generate maps for the left and right halves
    // map_L: XOR_sum -> Max size for the first half
    auto map_L = generate_map(nums, 0, N_L);
    // map_R: XOR_sum -> Max size for the second half
    auto map_R = generate_map(nums, N_L, N);

    // 2. Combine results
    // max_retained tracks the maximum total size (s_L + s_R) that results in the target XOR sum.
    // Initialize to -1 to detect if any valid combination was found.
    int max_retained = -1;

    for (const auto& pair_L : map_L) {
        long long x_L = pair_L.first;
        int s_L = pair_L.second;

        // We need x_R such that x_L ^ x_R = target, so x_R = x_L ^ target
        long long x_R_needed = x_L ^ target;

        if (map_R.count(x_R_needed)) {
            int s_R = map_R.at(x_R_needed);
            int total_size = s_L + s_R;

            if (total_size > max_retained) {
                max_retained = total_size;
            }
        }
    }

    // 3. Determine minimum removals
    if (max_retained == -1) {
        return -1;
    } else {
        // Minimum removals = Total size - Maximum retained size
        return N - max_retained;
    }
}
